              <div className="flex items-center justify-between text-slate-300 text-sm font-medium">
                <span className="flex items-center gap-2"><Home size={14} className="text-blue-400"/> Home</span>
                {savedLocations.home && <span className="text-green-400 text-xs">Set</span>}
