import React, { useState } from 'react';
import { Task } from '../types';
import { Trash2, Clock, MapPin, CheckCircle, Circle, Repeat, X, Check } from 'lucide-react';

interface TaskListProps {
  tasks: Task[];
  onDelete: (id: string) => void;
  onToggle: (id: string) => void;
  onUpdate: (task: Task) => void;
}

const TaskList: React.FC<TaskListProps> = ({ tasks, onDelete, onToggle, onUpdate }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Task>>({});

  const startEditing = (task: Task, e: React.MouseEvent) => {
    // Prevent editing if clicking specific controls
    if ((e.target as HTMLElement).closest('button')) return;

    setEditingId(task.id);
    setEditForm(task);
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditForm({});
  };

  const saveEditing = () => {
    if (editingId && editForm.description) {
       const original = tasks.find(t => t.id === editingId);
       if (original) {
           onUpdate({ ...original, ...editForm } as Task);
       }
       setEditingId(null);
    }
  };

  // Helper to format ISO string to datetime-local input format (YYYY-MM-DDThh:mm)
  const toInputFormat = (isoStr: string | null) => {
    if (!isoStr) return '';
    const d = new Date(isoStr);
    const pad = (n: number) => n < 10 ? '0'+n : n;
    return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
  };

  // Helper to format input value back to ISO
  const fromInputFormat = (val: string) => {
    if (!val) return null;
    return new Date(val).toISOString();
  };

  if (tasks.length === 0) {
    return (
      <div className="text-center text-gray-500 py-10">
        <p>No tasks yet. Try saying "Remind me to..."</p>
      </div>
    );
  }

  return (
    <div className="space-y-4 max-h-[60vh] overflow-y-auto pr-2">
      {tasks.map((task) => {
        const isEditing = editingId === task.id;

        if (isEditing) {
            return (
                <div key={task.id} className="bg-slate-800 p-4 rounded-xl border border-blue-500/50 flex flex-col gap-3 shadow-lg">
                    <textarea 
                        className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-slate-100 text-sm focus:border-blue-500 outline-none resize-none"
                        value={editForm.description || ''}
                        onChange={e => setEditForm({...editForm, description: e.target.value})}
                        placeholder="Task description"
                        rows={2}
                    />

                    <div className="grid grid-cols-2 gap-3">
                        <div className="flex flex-col gap-1">
                            <label className="text-[10px] uppercase text-slate-500 font-semibold tracking-wider">Due Date</label>
                            <input 
                                type="datetime-local"
                                className="bg-slate-900 border border-slate-700 rounded p-1.5 text-xs text-slate-300 focus:border-blue-500 outline-none"
                                value={toInputFormat(editForm.dueDateTime || null)}
                                onChange={e => setEditForm({...editForm, dueDateTime: fromInputFormat(e.target.value)})}
                            />
                        </div>
                        <div className="flex flex-col gap-1">
                            <label className="text-[10px] uppercase text-slate-500 font-semibold tracking-wider">Alarm</label>
                            <input 
                                type="datetime-local"
                                className="bg-slate-900 border border-slate-700 rounded p-1.5 text-xs text-slate-300 focus:border-blue-500 outline-none"
                                value={toInputFormat(editForm.alarmTime || null)}
                                onChange={e => setEditForm({...editForm, alarmTime: fromInputFormat(e.target.value)})}
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <div className="flex flex-col gap-1">
                            <label className="text-[10px] uppercase text-slate-500 font-semibold tracking-wider">Repeat</label>
                            <select 
                                className="bg-slate-900 border border-slate-700 rounded p-1.5 text-xs text-slate-300 focus:border-blue-500 outline-none"
                                value={editForm.recurrence || ''}
                                onChange={e => setEditForm({...editForm, recurrence: e.target.value || null})}
                            >
                                <option value="">None</option>
                                <option value="daily">Daily</option>
                                <option value="weekdays">Weekdays</option>
                                <option value="weekly">Weekly</option>
                                <option value="monthly">Monthly</option>
                            </select>
                        </div>
                        <div className="flex flex-col gap-1">
                            <label className="text-[10px] uppercase text-slate-500 font-semibold tracking-wider">Location</label>
                             <input 
                                type="text"
                                className="bg-slate-900 border border-slate-700 rounded p-1.5 text-xs text-slate-300 focus:border-blue-500 outline-none"
                                value={editForm.locationTrigger || ''}
                                onChange={e => setEditForm({...editForm, locationTrigger: e.target.value || null})}
                                placeholder="e.g. Home, Work"
                            />
                        </div>
                    </div>

                    <div className="flex justify-end gap-2 mt-2">
                        <button onClick={cancelEditing} className="p-1.5 rounded bg-slate-700 hover:bg-slate-600 text-slate-300 transition-colors">
                            <X size={16} />
                        </button>
                        <button onClick={saveEditing} className="p-1.5 rounded bg-green-700 hover:bg-green-600 text-white transition-colors">
                            <Check size={16} />
                        </button>
                    </div>
                </div>
            );
        }

        return (
            <div
            key={task.id}
            onClick={(e) => startEditing(task, e)}
            className={`relative group bg-slate-800 p-4 rounded-xl border border-slate-700 transition-all hover:border-blue-500/50 cursor-pointer ${task.completed ? 'opacity-50' : ''}`}
            >
            <div className="flex items-start gap-3">
                <button 
                onClick={(e) => { e.stopPropagation(); onToggle(task.id); }}
                className="mt-1 text-slate-400 hover:text-blue-400 transition-colors z-10"
                >
                {task.completed ? <CheckCircle size={20} /> : <Circle size={20} />}
                </button>

                <div className="flex-1 pointer-events-none">
                <p className={`text-lg font-medium text-slate-100 ${task.completed ? 'line-through decoration-slate-500' : ''}`}>
                    {task.description}
                </p>

                <div className="flex flex-wrap gap-2 mt-2">
                    {task.dueDateTime && (
                    <span className="inline-flex items-center text-xs px-2 py-1 rounded bg-slate-700 text-slate-300">
                        <Clock size={12} className="mr-1" />
                        Due: {new Date(task.dueDateTime).toLocaleString(undefined, {
                        month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit'
                        })}
