                    {task.alarmTime && (
                    <span className="inline-flex items-center text-xs px-2 py-1 rounded bg-indigo-900/50 text-indigo-300 border border-indigo-700/50">
                        <Clock size={12} className="mr-1" />
                        Alarm: {new Date(task.alarmTime).toLocaleString(undefined, {
                        hour: 'numeric', minute: '2-digit'
                        })}
                    </span>
                    )}

                    {task.recurrence && (
                    <span className="inline-flex items-center text-xs px-2 py-1 rounded bg-purple-900/50 text-purple-300 border border-purple-700/50 capitalize">
                        <Repeat size={12} className="mr-1" />
                        {task.recurrence}
                    </span>
                    )}

                    {task.locationTrigger && (
                    <span className="inline-flex items-center text-xs px-2 py-1 rounded bg-emerald-900/50 text-emerald-300 border border-emerald-700/50">
                        <MapPin size={12} className="mr-1" />
                        {task.locationTrigger}
                    </span>
                    )}
                </div>
                </div>

                <button
                onClick={(e) => { e.stopPropagation(); onDelete(task.id); }}
                className="p-2 text-slate-500 hover:text-red-400 hover:bg-slate-700 rounded-lg transition-colors opacity-0 group-hover:opacity-100 z-10"
                title="Delete task"
                >
                <Trash2 size={18} />
                </button>
            </div>
            </div>
        );
      })}
    </div>
  );
};

