    setEditingId(task.id);
    setEditForm(task);
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditForm({});
  };

  const saveEditing = () => {
    if (editingId && editForm.description) {
       const original = tasks.find(t => t.id === editingId);
       if (original) {
