              <button 
                onClick={() => setLocation('work')}
                className="mt-1 text-xs py-1.5 px-3 bg-slate-700 hover:bg-slate-600 rounded text-slate-200 transition-colors text-center"
              >
                Set Current Location
              </button>
            </div>
          </div>

          {currentCoords && (
             <div className="text-[10px] text-slate-600 font-mono">
               GPS: {currentCoords.latitude.toFixed(6)}, {currentCoords.longitude.toFixed(6)}
             </div>
          )}
        </div>

        {/* Simulation Tools for Demo */}
        <div className="mt-4 border-t border-slate-800 pt-4 opacity-75">
          <h3 className="text-xs font-semibold text-slate-600 mb-2 uppercase tracking-wider">Debug Simulation</h3>
          <div className="flex flex-wrap gap-3">
            <button 
              onClick={() => simulateLocationArrival('Home')}
              className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 hover:bg-slate-800 rounded text-xs text-slate-500 border border-slate-800 transition-colors"
            >
              Arrive Home
            </button>
            <button 
              onClick={() => simulateLocationArrival('Work')}
              className="flex items-center gap-2 px-3 py-1.5 bg-slate-800/50 hover:bg-slate-800 rounded text-xs text-slate-500 border border-slate-800 transition-colors"
            >
              Arrive Work
            </button>
          </div>
          {lastLocation && <p className="mt-2 text-xs text-slate-600">Last triggered: {lastLocation}</p>}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  GoogleGenAI, 
  LiveServerMessage, 
  Modality, 
  Type,
  FunctionDeclaration 
} from '@google/genai';
import { 
  Mic, 
  MicOff, 
  Loader2, 
  Volume2, 
  Navigation,
  BellRing,
  MapPin,
  Home,
  Briefcase,
  LogIn,
  LogOut,
  RefreshCw,
  Settings,
  X
} from 'lucide-react';

import TaskList from './components/TaskList';
import Visualizer from './components/Visualizer';
import { Task, ConnectionState, SavedLocations, Coordinates } from './types';
import { createPcmBlob, decodeAudioData, base64ToUint8Array } from './utils/audio';
import { calculateDistance } from './utils/geo';
import { generateSpeech, playAudioBuffer } from './services/geminiService';
import { fetchGoogleTasks, createGoogleTask, updateGoogleTask, deleteGoogleTask } from './services/googleTasksService';

const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-09-2025';

// Helper to safely get env vars
const getEnvVar = (key: string) => {
  if (typeof process !== 'undefined' && process.env) {
    return process.env[key] || process.env[`REACT_APP_${key}`] || process.env[`VITE_${key}`];
  }
  return undefined;
};

// Define tools
const addTaskTool: FunctionDeclaration = {
  name: 'addTask',
  description: 'Add a new task to the to-do list with optional due date, alarm time, location trigger, and recurrence.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      description: { type: Type.STRING, description: 'The polished, professional content of the task' },
      dueDateTime: { type: Type.STRING, description: 'ISO date string for when the task is due, if specified' },
      alarmTime: { type: Type.STRING, description: 'ISO date string for when to set an alarm, if specified' },
      locationTrigger: { type: Type.STRING, description: 'Description of location trigger (e.g. "home", "work")' },
      recurrence: { 
        type: Type.STRING, 
        description: 'Recurrence interval. Allowed values: "daily", "weekly", "weekdays", "monthly". Use this if the user says "every day", "recurring", etc.',
        enum: ['daily', 'weekly', 'weekdays', 'monthly']
      }
    },
    required: ['description']
  }
};

const removeTaskTool: FunctionDeclaration = {
  name: 'removeTask',
  description: 'Remove a task by identifying keywords from its description.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      keyword: { type: Type.STRING, description: 'Keyword to identify the task to remove' }
    },
    required: ['keyword']
  }
};

const getNextOccurrence = (date: Date, type: string): Date => {
  const next = new Date(date);
  switch (type.toLowerCase()) {
    case 'daily':
      next.setDate(next.getDate() + 1);
      break;
    case 'weekly':
      next.setDate(next.getDate() + 7);
      break;
    case 'weekdays':
      const day = next.getDay();
      if (day === 5) next.setDate(next.getDate() + 3); // Fri -> Mon
      else if (day === 6) next.setDate(next.getDate() + 2); // Sat -> Mon
      else next.setDate(next.getDate() + 1);
      break;
    case 'monthly':
      next.setMonth(next.getMonth() + 1);
      break;
    default:
      next.setDate(next.getDate() + 1); // Default to daily
      break;
  }
  return next;
};

const App: React.FC = () => {
  // State
  const [tasks, setTasks] = useState<Task[]>([]);
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [volume, setVolume] = useState<number>(0); // Visualizer volume
  const [lastLocation, setLastLocation] = useState<string | null>(null);
  const [savedLocations, setSavedLocations] = useState<SavedLocations>({});
  const [currentCoords, setCurrentCoords] = useState<Coordinates | null>(null);

  // Auth & Config State
  const [googleClientId, setGoogleClientId] = useState<string>('');
  const [showSettings, setShowSettings] = useState(false);
  const [accessToken, setAccessToken] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  // Refs for Audio/Session
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const processedAlarmsRef = useRef<Set<string>>(new Set());
  const tokenClientRef = useRef<any>(null);

  // Track if we are currently "at" a location to prevent repeated triggering
  const atLocationStateRef = useRef<{ home: boolean; work: boolean }>({ home: false, work: false });

  // Initialize Config
  useEffect(() => {
    // 1. Try Env Var
    const envId = getEnvVar('GOOGLE_CLIENT_ID');
    // 2. Try Local Storage
    const storedId = localStorage.getItem('gemini_google_client_id');

    if (envId) {
        setGoogleClientId(envId);
    } else if (storedId) {
        setGoogleClientId(storedId);
    } else {
        setShowSettings(true); // Prompt user if missing
    }
  }, []);

  // Initialize Google Auth once Client ID is available
  useEffect(() => {
    if ((window as any).google && googleClientId && googleClientId !== 'YOUR_CLIENT_ID_HERE') {
      try {
        tokenClientRef.current = (window as any).google.accounts.oauth2.initTokenClient({
            client_id: googleClientId,
            scope: 'https://www.googleapis.com/auth/tasks',
            callback: async (tokenResponse: any) => {
            if (tokenResponse && tokenResponse.access_token) {
                setAccessToken(tokenResponse.access_token);
                await syncWithGoogle(tokenResponse.access_token);
            }
            },
        });
      } catch (e) {
          console.error("Failed to init token client:", e);
      }
    }
  }, [googleClientId]);

  // Initialize audio context & load local data
  useEffect(() => {
    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

    // Load persisted tasks (only if not logged in initially)
    const saved = localStorage.getItem('gemini-tasks');
    if (saved && !accessToken) {
      try {
        setTasks(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load tasks", e);
      }
    }

    // Load persisted locations
    const savedLocs = localStorage.getItem('gemini-locations');
    if (savedLocs) {
      try {
        setSavedLocations(JSON.parse(savedLocs));
      } catch (e) {
        console.error("Failed to load locations", e);
      }
    }
  }, [accessToken]);

  // Save tasks on change (Local Backup)
  useEffect(() => {
    localStorage.setItem('gemini-tasks', JSON.stringify(tasks));
  }, [tasks]);

  // Save locations on change
  useEffect(() => {
    localStorage.setItem('gemini-locations', JSON.stringify(savedLocations));
  }, [savedLocations]);

  // Sync Logic
  const handleGoogleLogin = () => {
    if (tokenClientRef.current) {
      tokenClientRef.current.requestAccessToken();
    } else {
      if (!googleClientId) {
          setShowSettings(true);
      } else {
          alert("Google Identity Services not initialized. Check Client ID.");
      }
    }
  };

  const handleGoogleLogout = () => {
    const token = accessToken;
    if (token) {
      (window as any).google.accounts.oauth2.revoke(token, () => {
        setAccessToken(null);
        setTasks([]); 
        alert("Logged out and local tasks cleared.");
      });
    }
  };

  const syncWithGoogle = async (token: string) => {
    setIsSyncing(true);
    try {
      const gTasks = await fetchGoogleTasks(token);
      setTasks(gTasks);
    } catch (e) {
      console.error("Sync failed", e);
      setErrorMessage("Failed to sync with Google Tasks.");
    } finally {
      setIsSyncing(false);
    }
  };

  // Geolocation Tracking
  useEffect(() => {
    if (!navigator.geolocation) {
      console.warn("Geolocation is not supported by this browser.");
      return;
    }

    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        const coords: Coordinates = {
          latitude: position.coords.latitude,
          longitude: position.coords.longitude
        };
        setCurrentCoords(coords);
        checkLocationTriggers(coords);
      },
      (error) => {
        console.error("Geolocation error:", error);
      },
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
      }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, [savedLocations, tasks]);

  const checkLocationTriggers = (current: Coordinates) => {
    const TRIGGER_DISTANCE_METERS = 100;
    const RESET_DISTANCE_METERS = 150; 

    if (savedLocations.home) {
      const dist = calculateDistance(current, savedLocations.home);
      if (dist < TRIGGER_DISTANCE_METERS) {
        if (!atLocationStateRef.current.home) {
          atLocationStateRef.current.home = true;
          triggerLocationAlarms('home');
        }
      } else if (dist > RESET_DISTANCE_METERS) {
        atLocationStateRef.current.home = false;
      }
    }

    if (savedLocations.work) {
      const dist = calculateDistance(current, savedLocations.work);
      if (dist < TRIGGER_DISTANCE_METERS) {
        if (!atLocationStateRef.current.work) {
          atLocationStateRef.current.work = true;
          triggerLocationAlarms('work');
        }
      } else if (dist > RESET_DISTANCE_METERS) {
        atLocationStateRef.current.work = false;
      }
    }
  };

  const triggerLocationAlarms = async (locationType: string) => {
    console.log(`Arrived at ${locationType}`);
    setLastLocation(locationType.charAt(0).toUpperCase() + locationType.slice(1));

    for (const task of tasks) {
      if (task.completed) continue;

      const trigger = task.locationTrigger?.toLowerCase();
      if (trigger && trigger.includes(locationType)) {
        console.log(`Triggering location alarm for: ${task.description}`);
        const text = `Welcome ${locationType}. Reminder: ${task.description}`;

        generateSpeech(text).then(buffer => {
          if (buffer && audioContextRef.current) {
            playAudioBuffer(buffer, audioContextRef.current);
          } else {
            const utterance = new SpeechSynthesisUtterance(text);
            window.speechSynthesis.speak(utterance);
          }
        });
      }
    }
  };

  // Alarm Check Logic
  useEffect(() => {
    const interval = setInterval(async () => {
      const now = new Date();

      let tasksUpdated = false;
      const newTasks = [...tasks];

      for (let i = 0; i < newTasks.length; i++) {
        const task = newTasks[i];
        if (!task.alarmTime || task.completed) continue;

        const alarmDate = new Date(task.alarmTime);
        const alarmKey = `${task.id}-${task.alarmTime}`;
        const timeDiff = now.getTime() - alarmDate.getTime();

        if (timeDiff >= 0 && timeDiff < 60000 && !processedAlarmsRef.current.has(alarmKey)) {
          console.log("Triggering Alarm for:", task.description);
          processedAlarmsRef.current.add(alarmKey);

          const text = `Reminder: It is time to ${task.description}`;
          generateSpeech(text).then(buffer => {
            if (buffer && audioContextRef.current) {
              playAudioBuffer(buffer, audioContextRef.current);
            } else {
              const utterance = new SpeechSynthesisUtterance(text);
              window.speechSynthesis.speak(utterance);
            }
          });

          if (task.recurrence) {
            const nextDate = getNextOccurrence(alarmDate, task.recurrence);
            newTasks[i] = { ...task, alarmTime: nextDate.toISOString() };
            tasksUpdated = true;

            // Update remote if needed
            if (accessToken) {
                updateGoogleTask(accessToken, newTasks[i]);
            }
          }
        } 
        else if (timeDiff >= 60000 && task.recurrence) {
          let nextDate = new Date(alarmDate);
          while (nextDate <= now) {
            nextDate = getNextOccurrence(nextDate, task.recurrence);
          }
          newTasks[i] = { ...task, alarmTime: nextDate.toISOString() };
          tasksUpdated = true;
           if (accessToken) {
                updateGoogleTask(accessToken, newTasks[i]);
            }
        }
      }

      if (tasksUpdated) {
        setTasks(newTasks);
      }

    }, 5000); 

    return () => clearInterval(interval);
  }, [tasks, accessToken]);

  // Helper to manage tasks from tools
  const handleToolCall = useCallback(async (toolCall: any) => {
    const responses: any[] = [];

    for (const fc of toolCall.functionCalls) {
      console.log('Function Call:', fc.name, fc.args);
      let result = { result: 'ok' };

      if (fc.name === 'addTask') {
        const newTask: Task = {
          id: crypto.randomUUID(), // Temp ID, will be replaced by Google ID if synced
          description: fc.args.description,
          dueDateTime: fc.args.dueDateTime || null,
          alarmTime: fc.args.alarmTime || null,
          locationTrigger: fc.args.locationTrigger || null,
          recurrence: fc.args.recurrence || null,
          completed: false,
          createdAt: new Date().toISOString()
        };

        if (accessToken) {
            // Create on Google
            const googleId = await createGoogleTask(accessToken, newTask);
            if (googleId) newTask.id = googleId;
        }

        setTasks(prev => [...prev, newTask]);

        let msg = `Task added: ${newTask.description}`;
        if (newTask.recurrence) msg += ` (Repeat: ${newTask.recurrence})`;
        result = { result: msg };
      } else if (fc.name === 'removeTask') {
        const keyword = fc.args.keyword.toLowerCase();
        let removedCount = 0;

        // Find tasks to remove
        const toRemove = tasks.filter(t => t.description.toLowerCase().includes(keyword));
        removedCount = toRemove.length;

        // Optimistic update
        setTasks(prev => prev.filter(t => !t.description.toLowerCase().includes(keyword)));

        // Async remove from Google
        if (accessToken) {
            toRemove.forEach(t => deleteGoogleTask(accessToken, t.id));
        }

        result = { result: removedCount > 0 ? `Removed ${removedCount} tasks matching "${keyword}"` : `No tasks found matching "${keyword}"` };
      }

      responses.push({
        id: fc.id,
        name: fc.name,
        response: result
      });
    }

    return responses;
  }, [tasks, accessToken]);

  const connect = useCallback(async () => {
    if (!process.env.API_KEY) {
      setErrorMessage("API Key not found in environment variables.");
      return;
    }
    setErrorMessage(null);
    setConnectionState(ConnectionState.CONNECTING);

    if (audioContextRef.current?.state === 'suspended') {
      try { await audioContextRef.current.resume(); } catch (e) { console.warn(e); }
    }
    if (inputContextRef.current?.state === 'suspended') {
      try { await inputContextRef.current.resume(); } catch (e) { console.warn(e); }
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        callbacks: {
          onopen: () => {
            console.log("Session Opened");
            setConnectionState(ConnectionState.CONNECTED);

            if (!inputContextRef.current) return;

            const source = inputContextRef.current.createMediaStreamSource(stream);
            const processor = inputContextRef.current.createScriptProcessor(4096, 1, 1);

            sourceRef.current = source;
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0;
              for(let i=0; i<inputData.length; i++) sum += inputData[i] * inputData[i];
              setVolume(Math.sqrt(sum / inputData.length) * 500);

              const blob = createPcmBlob(inputData);
              sessionPromiseRef.current?.then(session => {
                session.sendRealtimeInput({ media: blob });
              });
            };

            source.connect(processor);
            processor.connect(inputContextRef.current.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.toolCall) {
              const functionResponses = await handleToolCall(message.toolCall);
              sessionPromiseRef.current?.then(session => {
                session.sendToolResponse({ functionResponses });
              });
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && audioContextRef.current) {
              const ctx = audioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const audioBuffer = await decodeAudioData(
                base64ToUint8Array(base64Audio),
                ctx
              );

              const source = ctx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
            }
          },
          onclose: () => {
            console.log("Session Closed");
            setConnectionState(ConnectionState.DISCONNECTED);
          },
          onerror: (err) => {
            console.error("Session Error", err);
            setErrorMessage("Connection error occurred.");
            setConnectionState(ConnectionState.ERROR);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: `
            You are a helpful personal assistant managing a To-Do list.
            The current date and time is ${new Date().toLocaleString()}.
            Use the provided tools to manage tasks.

            CRITICAL INSTRUCTION FOR ADDING TASKS:
            When the user asks to add a task, you must:
            1. Listen carefully to their natural language input, which may be messy or rambling.
            2. Infer the true underlying intent of the task.
            3. REWRITE the task description to be professional, polished, concise, and grammatically correct before calling the 'addTask' tool.
            4. Do not simply transcribe what they said. Improve it.

            If the user asks to add a task, ask clarifying questions if the time or location is vague, but don't be annoying.
            If the user says "every day", "daily", "every week", etc., set the 'recurrence' parameter in addTask.
            Be concise in your spoken responses.
          `,
          tools: [{ functionDeclarations: [addTaskTool, removeTaskTool] }]
        }
      });

      sessionPromiseRef.current = sessionPromise;

    } catch (err) {
      console.error(err);
      setConnectionState(ConnectionState.ERROR);
      setErrorMessage("Failed to connect to microphone or API.");
    }
  }, [handleToolCall]);

  const disconnect = useCallback(async () => {
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current.onaudioprocess = null;
      processorRef.current = null;
    }
    if (sourceRef.current) {
      sourceRef.current.disconnect();
      sourceRef.current = null;
    }
    if (sessionPromiseRef.current) {
      await sessionPromiseRef.current;
    }
    window.location.reload(); 
  }, []);

  const setLocation = (type: 'home' | 'work') => {
    if (!currentCoords) {
      alert("Current location not available yet. Please wait for GPS.");
      return;
    }
    setSavedLocations(prev => ({ ...prev, [type]: currentCoords }));
    atLocationStateRef.current[type] = false;
  };

  const simulateLocationArrival = async (location: string) => {
    triggerLocationAlarms(location.toLowerCase());
  };

  const toggleTask = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;

    const updated = { ...task, completed: !task.completed };
    setTasks(prev => prev.map(t => t.id === id ? updated : t));

    if (accessToken) {
        updateGoogleTask(accessToken, updated);
    }
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    if (accessToken) {
        deleteGoogleTask(accessToken, id);
    }
  };

  const updateTask = (updatedTask: Task) => {
    setTasks(prev => prev.map(t => t.id === updatedTask.id ? updatedTask : t));
    if (accessToken) {
        updateGoogleTask(accessToken, updatedTask);
    }
  };

  // Handle URL parameters for external automation (e.g. Tasker)
  useEffect(() => {
    const handleUrlParams = async () => {
      const params = new URLSearchParams(window.location.search);
      const action = params.get('action');

      if (!action) return;

      if (action === 'addTask') {
        const description = params.get('description');
        if (description) {
          const newTask: Task = {
            id: crypto.randomUUID(),
            description: decodeURIComponent(description),
            dueDateTime: params.get('dueDateTime') || null,
            alarmTime: params.get('alarmTime') || null,
            locationTrigger: params.get('locationTrigger') || null,
            recurrence: params.get('recurrence') || null,
            completed: false,
            createdAt: new Date().toISOString()
          };

          if (accessToken) {
              const googleId = await createGoogleTask(accessToken, newTask);
              if (googleId) newTask.id = googleId;
          }

          setTasks(prev => [...prev, newTask]);
          window.history.replaceState({}, '', window.location.pathname);
        }
      } else if (action === 'startVoice') {
        connect();
        window.history.replaceState({}, '', window.location.pathname);
      }
    };

    handleUrlParams();
  }, [connect, accessToken]);

  const saveClientId = (id: string) => {
      setGoogleClientId(id);
      localStorage.setItem('gemini_google_client_id', id);
      setShowSettings(false);
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-50 flex flex-col items-center p-6 relative">

      {/* Settings Modal */}
      {showSettings && (
          <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex items-center justify-center p-4">
              <div className="bg-slate-800 border border-slate-700 p-6 rounded-2xl w-full max-w-md shadow-2xl relative">
                  <button 
                    onClick={() => setShowSettings(false)}
                    className="absolute right-4 top-4 text-slate-400 hover:text-white"
                  >
                      <X size={20} />
                  </button>
                  <h2 className="text-xl font-bold mb-4 text-white">App Configuration</h2>
                  <p className="text-sm text-slate-400 mb-4">
                      To sync with Google Tasks, you need a Google Cloud Project with the Tasks API enabled.
                  </p>

                  <div className="flex flex-col gap-2">
                      <label className="text-xs font-bold text-slate-400 uppercase">Google Client ID</label>
                      <input 
                        type="text" 
                        placeholder="1234...apps.googleusercontent.com"
                        className="bg-slate-900 border border-slate-700 p-3 rounded-lg text-sm text-white focus:border-blue-500 outline-none"
                        value={googleClientId === 'YOUR_CLIENT_ID_HERE' ? '' : googleClientId}
                        onChange={(e) => setGoogleClientId(e.target.value)}
                      />
                  </div>

                  <div className="mt-6 flex justify-end">
                      <button 
                        onClick={() => saveClientId(googleClientId)}
                        className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                      >
                          Save Configuration
                      </button>
                  </div>
              </div>
          </div>
      )}

      <header className="w-full max-w-2xl flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold bg-gradient-to-r from-blue-400 to-purple-500 bg-clip-text text-transparent">
            Gemini Assistant
          </h1>
