// Helper to safely get env vars
const getEnvVar = (key: string) => {
  if (typeof process !== 'undefined' && process.env) {
    return process.env[key] || process.env[`REACT_APP_${key}`] || process.env[`VITE_${key}`];
  }
  return undefined;
};

// Define tools
const addTaskTool: FunctionDeclaration = {
  name: 'addTask',
  description: 'Add a new task to the to-do list with optional due date, alarm time, location trigger, and recurrence.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      description: { type: Type.STRING, description: 'The polished, professional content of the task' },
      dueDateTime: { type: Type.STRING, description: 'ISO date string for when the task is due, if specified' },
      alarmTime: { type: Type.STRING, description: 'ISO date string for when to set an alarm, if specified' },
      locationTrigger: { type: Type.STRING, description: 'Description of location trigger (e.g. "home", "work")' },
      recurrence: { 
        type: Type.STRING, 
        description: 'Recurrence interval. Allowed values: "daily", "weekly", "weekdays", "monthly". Use this if the user says "every day", "recurring", etc.',
        enum: ['daily', 'weekly', 'weekdays', 'monthly']
      }
    },
    required: ['description']
  }
};

const removeTaskTool: FunctionDeclaration = {
  name: 'removeTask',
  description: 'Remove a task by identifying keywords from its description.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      keyword: { type: Type.STRING, description: 'Keyword to identify the task to remove' }
    },
    required: ['keyword']
  }
};

const getNextOccurrence = (date: Date, type: string): Date => {
  const next = new Date(date);
  switch (type.toLowerCase()) {
    case 'daily':
      next.setDate(next.getDate() + 1);
      break;
    case 'weekly':
      next.setDate(next.getDate() + 7);
      break;
    case 'weekdays':
      const day = next.getDay();
      if (day === 5) next.setDate(next.getDate() + 3); // Fri -> Mon
      else if (day === 6) next.setDate(next.getDate() + 2); // Sat -> Mon
      else next.setDate(next.getDate() + 1);
      break;
    case 'monthly':
      next.setMonth(next.getMonth() + 1);
      break;
    default:
      next.setDate(next.getDate() + 1); // Default to daily
      break;
  }
  return next;
};

const App: React.FC = () => {
