  const inputContextRef = useRef<AudioContext | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const processedAlarmsRef = useRef<Set<string>>(new Set());
  const tokenClientRef = useRef<any>(null);

  // Track if we are currently "at" a location to prevent repeated triggering
  const atLocationStateRef = useRef<{ home: boolean; work: boolean }>({ home: false, work: false });

  // Initialize Config
  useEffect(() => {
    // 1. Try Env Var
    const envId = getEnvVar('GOOGLE_CLIENT_ID');
