// Helper to safely get env vars
const getEnvVar = (key: string) => {
  if (typeof process !== 'undefined' && process.env) {
    return process.env[key] || process.env[`REACT_APP_${key}`] || process.env[`VITE_${key}`];
  }
  return undefined;
};

// Define tools
const addTaskTool: FunctionDeclaration = {
  name: 'addTask',
  description: 'Add a new task to the to-do list with optional due date, alarm time, location trigger, and recurrence.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      description: { type: Type.STRING, description: 'The polished, professional content of the task' },
      dueDateTime: { type: Type.STRING, description: 'ISO date string for when the task is due, if specified' },
      alarmTime: { type: Type.STRING, description: 'ISO date string for when to set an alarm, if specified' },
      locationTrigger: { type: Type.STRING, description: 'Description of location trigger (e.g. "home", "work")' },
      recurrence: { 
        type: Type.STRING, 
        description: 'Recurrence interval. Allowed values: "daily", "weekly", "weekdays", "monthly". Use this if the user says "every day", "recurring", etc.',
        enum: ['daily', 'weekly', 'weekdays', 'monthly']
      }
    },
    required: ['description']
  }
};

const removeTaskTool: FunctionDeclaration = {
  name: 'removeTask',
  description: 'Remove a task by identifying keywords from its description.',
  parameters: {
    type: Type.OBJECT,
    properties: {
      keyword: { type: Type.STRING, description: 'Keyword to identify the task to remove' }
    },
    required: ['keyword']
  }
};

const getNextOccurrence = (date: Date, type: string): Date => {
  const next = new Date(date);
  switch (type.toLowerCase()) {
    case 'daily':
      next.setDate(next.getDate() + 1);
      break;
    case 'weekly':
      next.setDate(next.getDate() + 7);
      break;
    case 'weekdays':
      const day = next.getDay();
      if (day === 5) next.setDate(next.getDate() + 3); // Fri -> Mon
      else if (day === 6) next.setDate(next.getDate() + 2); // Sat -> Mon
      else next.setDate(next.getDate() + 1);
      break;
    case 'monthly':
      next.setMonth(next.getMonth() + 1);
      break;
    default:
      next.setDate(next.getDate() + 1); // Default to daily
      break;
  }
  return next;
};

const App: React.FC = () => {
  // State
  const [tasks, setTasks] = useState<Task[]>([]);
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [volume, setVolume] = useState<number>(0); 
  const [lastLocation, setLastLocation] = useState<string | null>(null);
  const [savedLocations, setSavedLocations] = useState<SavedLocations>({});
  const [currentCoords, setCurrentCoords] = useState<Coordinates | null>(null);

  // Auth & Config State
  const [googleClientId, setGoogleClientId] = useState<string>('');
  const [showSettings, setShowSettings] = useState(false);
  const [accessToken, setAccessToken] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [origin, setOrigin] = useState<string>('');
  const [originChanged, setOriginChanged] = useState(false);
  const [previousOrigin, setPreviousOrigin] = useState('');

  // Refs for Audio/Session
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const processedAlarmsRef = useRef<Set<string>>(new Set());
  const tokenClientRef = useRef<any>(null);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const atLocationStateRef = useRef<{ home: boolean; work: boolean }>({ home: false, work: false });

  useEffect(() => {
    const envId = getEnvVar('GOOGLE_CLIENT_ID');
    const storedId = localStorage.getItem('gemini_google_client_id');

    if (envId) setGoogleClientId(envId);
    else if (storedId) setGoogleClientId(storedId);
    else setShowSettings(true);

    const currentOrigin = window.location.origin;
    setOrigin(currentOrigin);

    const savedOrigin = localStorage.getItem('gemini_app_origin');
    if (savedOrigin && savedOrigin !== currentOrigin) {
        setOriginChanged(true);
        setPreviousOrigin(savedOrigin);
        setShowSettings(true);
    }
    localStorage.setItem('gemini_app_origin', currentOrigin);
  }, []);

  useEffect(() => {
    if ((window as any).google && googleClientId && googleClientId !== 'YOUR_CLIENT_ID_HERE') {
      try {
        tokenClientRef.current = (window as any).google.accounts.oauth2.initTokenClient({
            client_id: googleClientId,
            scope: 'https://www.googleapis.com/auth/tasks',
            callback: async (tokenResponse: any) => {
                if (tokenResponse.error) {
                    setErrorMessage(`Google Auth Error: ${tokenResponse.error_description || tokenResponse.error}`);
                    if (tokenResponse.error === 'origin_mismatch') setShowSettings(true);
                    return;
                }
                if (tokenResponse && tokenResponse.access_token) {
                    setAccessToken(tokenResponse.access_token);
                    setErrorMessage(null);
                    await syncWithGoogle(tokenResponse.access_token);
                }
            },
        });
      } catch (e) { console.error("OAuth init failed", e); }
    }
  }, [googleClientId]);

  useEffect(() => {
    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    inputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

    const saved = localStorage.getItem('gemini-tasks');
    if (saved && !accessToken) {
      try { setTasks(JSON.parse(saved)); } catch (e) {}
    }

    const savedLocs = localStorage.getItem('gemini-locations');
    if (savedLocs) {
      try { setSavedLocations(JSON.parse(savedLocs)); } catch (e) {}
    }
  }, [accessToken]);

  useEffect(() => { localStorage.setItem('gemini-tasks', JSON.stringify(tasks)); }, [tasks]);
  useEffect(() => { localStorage.setItem('gemini-locations', JSON.stringify(savedLocations)); }, [savedLocations]);

  const handleGoogleLogin = () => {
    if (tokenClientRef.current) {
      setErrorMessage(null);
      tokenClientRef.current.requestAccessToken();
    } else setShowSettings(true);
  };

  const handleGoogleLogout = () => {
    if (accessToken) {
      (window as any).google.accounts.oauth2.revoke(accessToken, () => {
        setAccessToken(null);
        setTasks([]); 
      });
    }
  };

  const syncWithGoogle = async (token: string) => {
    setIsSyncing(true);
    try {
      const gTasks = await fetchGoogleTasks(token);
      setTasks(gTasks);
    } catch (e) { setErrorMessage("Sync failed with Google Tasks."); }
    finally { setIsSyncing(false); }
  };

  useEffect(() => {
    if (!navigator.geolocation) return;
    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        const coords = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
        setCurrentCoords(coords);
        checkLocationTriggers(coords);
      },
      (err) => console.error(err),
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, [savedLocations, tasks]);

  const checkLocationTriggers = (current: Coordinates) => {
    const TRIGGER_DISTANCE = 100;
    const RESET_DISTANCE = 150; 

    (['home', 'work'] as const).forEach(loc => {
      if (savedLocations[loc]) {
        const dist = calculateDistance(current, savedLocations[loc]!);
        if (dist < TRIGGER_DISTANCE && !atLocationStateRef.current[loc]) {
          atLocationStateRef.current[loc] = true;
          triggerLocationAlarms(loc);
        } else if (dist > RESET_DISTANCE) {
          atLocationStateRef.current[loc] = false;
        }
      }
    });
  };

  const triggerLocationAlarms = async (locationType: string) => {
    setLastLocation(locationType.charAt(0).toUpperCase() + locationType.slice(1));
    for (const task of tasks) {
      if (task.completed) continue;
      if (task.locationTrigger?.toLowerCase().includes(locationType)) {
        const text = `Arrived at ${locationType}. Reminder: ${task.description}`;
        generateSpeech(text).then(buffer => {
          if (buffer && audioContextRef.current) playAudioBuffer(buffer, audioContextRef.current);
          else window.speechSynthesis.speak(new SpeechSynthesisUtterance(text));
        });
      }
    }
  };

  useEffect(() => {
    const interval = setInterval(async () => {
      const now = new Date();
      let updated = false;
      const newTasks = [...tasks];
      for (let i = 0; i < newTasks.length; i++) {
        const task = newTasks[i];
        if (!task.alarmTime || task.completed) continue;
        const alarmDate = new Date(task.alarmTime);
        const alarmKey = `${task.id}-${task.alarmTime}`;
        if (now >= alarmDate && !processedAlarmsRef.current.has(alarmKey)) {
          processedAlarmsRef.current.add(alarmKey);
          const text = `Reminder: ${task.description}`;
          generateSpeech(text).then(buf => {
            if (buf && audioContextRef.current) playAudioBuffer(buf, audioContextRef.current);
            else window.speechSynthesis.speak(new SpeechSynthesisUtterance(text));
          });
          if (task.recurrence) {
            newTasks[i] = { ...task, alarmTime: getNextOccurrence(alarmDate, task.recurrence).toISOString() };
            updated = true;
            if (accessToken) updateGoogleTask(accessToken, newTasks[i]);
          }
        }
      }
      if (updated) setTasks(newTasks);
    }, 5000);
    return () => clearInterval(interval);
  }, [tasks, accessToken]);

  const handleToolCall = useCallback(async (toolCall: any) => {
    const responses: any[] = [];
    for (const fc of toolCall.functionCalls) {
      let result = { result: 'ok' };
      if (fc.name === 'addTask') {
        const newTask: Task = {
          id: crypto.randomUUID(),
          description: fc.args.description,
          dueDateTime: fc.args.dueDateTime || null,
          alarmTime: fc.args.alarmTime || null,
          locationTrigger: fc.args.locationTrigger || null,
          recurrence: fc.args.recurrence || null,
          completed: false,
          createdAt: new Date().toISOString()
        };
        if (accessToken) {
          const gId = await createGoogleTask(accessToken, newTask);
          if (gId) newTask.id = gId;
        }
        setTasks(prev => [...prev, newTask]);
        result = { result: `Task saved: ${newTask.description}` };
      } else if (fc.name === 'removeTask') {
        const keyword = fc.args.keyword.toLowerCase();
        const toRemove = tasks.filter(t => t.description.toLowerCase().includes(keyword));
        setTasks(prev => prev.filter(t => !t.description.toLowerCase().includes(keyword)));
        if (accessToken) toRemove.forEach(t => deleteGoogleTask(accessToken, t.id));
        result = { result: `Deleted ${toRemove.length} matching tasks.` };
      }
      responses.push({ id: fc.id, name: fc.name, response: result });
    }
    return responses;
  }, [tasks, accessToken]);

  const connect = useCallback(async () => {
    const apiKey = getEnvVar('API_KEY');
    if (!apiKey) {
      setErrorMessage("API Key missing from environment.");
      return;
    }
    setErrorMessage(null);
    setConnectionState(ConnectionState.CONNECTING);

    if (audioContextRef.current?.state === 'suspended') await audioContextRef.current.resume();
    if (inputContextRef.current?.state === 'suspended') await inputContextRef.current.resume();

    try {
      const ai = new GoogleGenAI({ apiKey });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        callbacks: {
          onopen: () => {
            setConnectionState(ConnectionState.CONNECTED);
            const source = inputContextRef.current!.createMediaStreamSource(stream);
            const processor = inputContextRef.current!.createScriptProcessor(4096, 1, 1);
            sourceRef.current = source;
            processorRef.current = processor;
            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0;
              for(let i=0; i<inputData.length; i++) sum += inputData[i] * inputData[i];
              setVolume(Math.sqrt(sum / inputData.length));
              sessionPromiseRef.current?.then(s => s.sendRealtimeInput({ media: createPcmBlob(inputData) }));
            };
            source.connect(processor);
            processor.connect(inputContextRef.current!.destination);
          },
          onmessage: async (msg) => {
            if (msg.toolCall) {
              const res = await handleToolCall(msg.toolCall);
              sessionPromiseRef.current?.then(s => s.sendToolResponse({ functionResponses: res }));
            }
            const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
              const ctx = audioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(base64ToUint8Array(audioData), ctx);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.onended = () => audioSourcesRef.current.delete(source);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              audioSourcesRef.current.add(source);
            }
            if (msg.serverContent?.interrupted) {
              audioSourcesRef.current.forEach(s => s.stop());
              audioSourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => setConnectionState(ConnectionState.DISCONNECTED),
          onerror: () => { setErrorMessage("Session error."); setConnectionState(ConnectionState.ERROR); }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: `You are a spatial assistant in an antigravity environment. Be professional, concise, and futuristic. Improve task descriptions before saving. Time: ${new Date().toLocaleString()}`,
          tools: [{ functionDeclarations: [addTaskTool, removeTaskTool] }]
        }
      });
      sessionPromiseRef.current = sessionPromise;
    } catch (e) { setConnectionState(ConnectionState.ERROR); }
  }, [handleToolCall]);

  const disconnect = useCallback(() => {
    processorRef.current?.disconnect();
    sourceRef.current?.disconnect();
    window.location.reload(); 
  }, []);

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-8">

      {/* Configuration Hub */}
      {showSettings && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
              <div className="glass border-blue-500/30 p-8 rounded-3xl w-full max-w-lg shadow-2xl relative">
                  <button onClick={() => setShowSettings(false)} className="absolute right-6 top-6 text-slate-400 hover:text-white"><X size={24} /></button>
                  <h2 className="text-2xl font-bold mb-2 flex items-center gap-3"><Sparkles className="text-blue-400"/> Assistant Configuration</h2>

                  {originChanged && (
                      <div className="bg-red-500/20 border border-red-500/50 p-4 rounded-xl mb-6 text-xs text-red-100">
                          <strong className="flex items-center gap-2 mb-1"><AlertTriangle size={14} /> Origin Changed</strong>
                          Update your Authorized JavaScript Origins in the Google Cloud Console to:
                          <div className="mt-2 bg-black/40 p-2 rounded font-mono text-green-300 break-all select-all">{origin}</div>
                      </div>
                  )}

                  <div className="space-y-6">
                      <div className="flex flex-col gap-2">
                          <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Google Client ID</label>
                          <input 
                            type="text" 
                            className="bg-slate-900/60 border border-slate-700 p-3 rounded-xl text-sm focus:border-blue-500 outline-none transition-all"
                            value={googleClientId}
                            onChange={(e) => setGoogleClientId(e.target.value)}
                          />
                      </div>
                      <a href="https://console.cloud.google.com/apis/credentials" target="_blank" className="flex items-center justify-center gap-2 p-3 bg-slate-700/50 hover:bg-slate-700 rounded-xl text-xs transition-colors"><ExternalLink size={14}/> Google Console</a>
                      <button onClick={() => { localStorage.setItem('gemini_google_client_id', googleClientId); setShowSettings(false); }} className="w-full bg-blue-600 hover:bg-blue-500 p-4 rounded-xl font-bold transition-all shadow-lg shadow-blue-600/20">Initialize Projection</button>
                  </div>
              </div>
          </div>
      )}

      {/* App Shell */}
      <header className="w-full max-w-3xl flex justify-between items-center mb-10">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 glass rounded-2xl flex items-center justify-center shadow-lg border-blue-400/20">
            <Sparkles className="text-blue-400" />
          </div>
          <div>
            <h1 className="text-3xl font-black tracking-tighter text-white">ANTIGRAVITY <span className="text-blue-500">VOICE</span></h1>
            <p className="text-slate-500 text-xs font-medium tracking-widest uppercase">Spatial Task Matrix</p>
          </div>
        </div>

        <div className="flex gap-3">
          <button onClick={() => setShowSettings(true)} className="w-10 h-10 glass rounded-xl flex items-center justify-center text-slate-400 hover:text-white transition-all"><Settings size={18}/></button>
          {accessToken ? (
            <button onClick={handleGoogleLogout} className="px-4 glass rounded-xl text-xs font-bold border-red-500/20 hover:bg-red-500/10 transition-all">SIGN OUT</button>
          ) : (
            <button onClick={handleGoogleLogin} className="px-4 glass bg-white/10 hover:bg-white/20 rounded-xl text-xs font-bold transition-all">SYNC CLOUD</button>
          )}
          <div className={`px-4 flex items-center glass rounded-xl text-[10px] font-black tracking-widest ${connectionState === ConnectionState.CONNECTED ? 'text-green-400' : 'text-slate-500'}`}>{connectionState}</div>
        </div>
      </header>

      <main className="w-full max-w-3xl flex flex-col gap-10">

        {/* Core Control Unit */}
        <div className="glass rounded-[40px] p-10 flex flex-col items-center gap-10 shadow-2xl relative overflow-hidden group">
          <div className="absolute inset-0 bg-gradient-to-b from-blue-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

          <div className="relative">
            <div className={`absolute inset-0 bg-blue-500 rounded-full blur-[60px] transition-all duration-1000 ${connectionState === ConnectionState.CONNECTED ? 'opacity-40 scale-150 animate-pulse' : 'opacity-10'}`} />
            <button
              onClick={connectionState === ConnectionState.CONNECTED ? disconnect : connect}
              className={`relative z-10 w-32 h-32 rounded-full flex items-center justify-center transition-all duration-500 ${
                connectionState === ConnectionState.CONNECTED ? 'bg-red-500 shadow-[0_0_50px_rgba(239,68,68,0.5)] rotate-90' : 'bg-blue-600 shadow-[0_0_50px_rgba(37,99,235,0.5)]'
              }`}
            >
              {connectionState === ConnectionState.CONNECTED ? <MicOff size={48} /> : <Mic size={48} />}
            </button>
          </div>

          <Visualizer isActive={volume > 0.05} />

          {errorMessage && <div className="text-red-400 text-xs font-bold tracking-widest uppercase bg-red-500/10 px-6 py-2 rounded-full border border-red-500/30">{errorMessage}</div>}
        </div>

        {/* Matrix View */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
          <div className="lg:col-span-8 space-y-6">
            <div className="flex justify-between items-center px-4">
              <h2 className="text-xl font-bold text-white flex items-center gap-3">TASK MATRIX</h2>
              {isSyncing && <Loader2 className="animate-spin text-blue-400" size={16} />}
            </div>
            <TaskList tasks={tasks} onDelete={(id) => setTasks(t => t.filter(x => x.id !== id))} onToggle={(id) => setTasks(t => t.map(x => x.id === id ? {...x, completed: !x.completed} : x))} onUpdate={(ut) => setTasks(t => t.map(x => x.id === ut.id ? ut : x))} />
          </div>

          <div className="lg:col-span-4 space-y-8">
            <div className="glass rounded-3xl p-6 space-y-6">
               <h3 className="text-xs font-black tracking-widest text-slate-500 uppercase">Proximity Anchors</h3>
               <div className="space-y-4">
                  <button onClick={() => setCurrentCoords(c => c && (setSavedLocations(s => ({...s, home: c})), c))} className="w-full glass-card glass p-4 rounded-2xl flex flex-col gap-1 items-start group">
                    <span className="text-[10px] font-black text-slate-500 group-hover:text-blue-400 transition-colors uppercase">Set Home Node</span>
                    <span className="text-sm font-bold text-white flex items-center gap-2"><Home size={14}/> Home Base</span>
                  </button>
                  <button onClick={() => setCurrentCoords(c => c && (setSavedLocations(s => ({...s, work: c})), c))} className="w-full glass-card glass p-4 rounded-2xl flex flex-col gap-1 items-start group">
                    <span className="text-[10px] font-black text-slate-500 group-hover:text-purple-400 transition-colors uppercase">Set Work Node</span>
                    <span className="text-sm font-bold text-white flex items-center gap-2"><Briefcase size={14}/> Work Hub</span>
                  </button>
               </div>
            </div>

            <div className="glass rounded-3xl p-6">
              <h3 className="text-xs font-black tracking-widest text-slate-500 uppercase mb-4">Neural Feedback</h3>
              <div className="flex flex-wrap gap-2">
                <button onClick={() => triggerLocationAlarms('home')} className="px-3 py-1.5 glass rounded-lg text-[10px] font-bold hover:bg-white/10 transition-colors">TEST HOME</button>
                <button onClick={() => triggerLocationAlarms('work')} className="px-3 py-1.5 glass rounded-lg text-[10px] font-bold hover:bg-white/10 transition-colors">TEST WORK</button>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Task } from '../types';
import { Trash2, Clock, MapPin, CheckCircle, Circle, Repeat, X, Check, BellRing, ChevronDown } from 'lucide-react';

interface TaskListProps {
  tasks: Task[];
  onDelete: (id: string) => void;
  onToggle: (id: string) => void;
  onUpdate: (task: Task) => void;
}

const TaskList: React.FC<TaskListProps> = ({ tasks, onDelete, onToggle, onUpdate }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Task>>({});

  const startEditing = (task: Task, e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('button')) return;
    setEditingId(task.id);
    setEditForm(task);
  };

  const toInputFormat = (isoStr: string | null) => {
    if (!isoStr) return '';
    const d = new Date(isoStr);
    const pad = (n: number) => n < 10 ? '0'+n : n;
    return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
  };

  if (tasks.length === 0) {
    return (
      <div className="glass rounded-3xl p-12 text-center text-slate-500">
        <p className="text-sm font-medium tracking-widest uppercase">Matrix Empty</p>
      </div>
    );
  }

  return (
    <div className="space-y-4 pb-20">
      {tasks.map((task) => {
        const isEditing = editingId === task.id;
        if (isEditing) {
            return (
                <div key={task.id} className="glass p-8 rounded-3xl border-2 border-blue-500 shadow-2xl space-y-6">
                    <div className="space-y-2">
                         <label className="text-[10px] font-black text-blue-400 uppercase tracking-widest">Entry Content</label>
                         <textarea 
                            className="w-full bg-black/30 border border-white/10 rounded-xl p-4 text-white focus:border-blue-500 outline-none resize-none transition-all"
                            value={editForm.description || ''}
                            onChange={e => setEditForm({...editForm, description: e.target.value})}
                            rows={2}
                            autoFocus
                        />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <input type="datetime-local" className="bg-black/30 border border-white/10 rounded-xl p-3 text-xs text-white" value={toInputFormat(editForm.dueDateTime || null)} onChange={e => setEditForm({...editForm, dueDateTime: new Date(e.target.value).toISOString()})} />
                        <select className="bg-black/30 border border-white/10 rounded-xl p-3 text-xs text-white" value={editForm.recurrence || ''} onChange={e => setEditForm({...editForm, recurrence: e.target.value || null})}>
                            <option value="">No Repeat</option>
                            <option value="daily">Daily</option>
                            <option value="weekly">Weekly</option>
                        </select>
                    </div>
                    <div className="flex justify-end gap-3 pt-4">
                        <button onClick={() => setEditingId(null)} className="px-6 py-2 glass rounded-xl text-xs font-bold">CANCEL</button>
                        <button onClick={() => { onUpdate({...task, ...editForm} as Task); setEditingId(null); }} className="px-6 py-2 bg-blue-600 rounded-xl text-xs font-bold text-white shadow-lg shadow-blue-600/20">SAVE MATRIX</button>
                    </div>
                </div>
            );
        }

        return (
            <div
              key={task.id}
              onClick={(e) => startEditing(task, e)}
              className={`glass-card glass p-6 rounded-2xl group cursor-pointer border-white/5 transition-all ${task.completed ? 'opacity-30' : ''}`}
            >
              <div className="flex items-start gap-4">
                <button onClick={(e) => { e.stopPropagation(); onToggle(task.id); }} className={`mt-1 transition-colors ${task.completed ? 'text-green-400' : 'text-slate-500 hover:text-blue-400'}`}>
                    {task.completed ? <CheckCircle size={24} /> : <Circle size={24} />}
                </button>
                <div className="flex-1">
                  <p className={`text-lg font-bold tracking-tight text-white ${task.completed ? 'line-through decoration-white/20' : ''}`}>{task.description}</p>
                  <div className="flex flex-wrap gap-2 mt-4">
                    {task.alarmTime && <span className="glass px-3 py-1.5 rounded-lg text-[10px] font-black text-blue-300 flex items-center gap-1.5 uppercase tracking-tighter"><BellRing size={10}/> {new Date(task.alarmTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>}
                    {task.locationTrigger && <span className="glass px-3 py-1.5 rounded-lg text-[10px] font-black text-emerald-300 flex items-center gap-1.5 uppercase tracking-tighter"><MapPin size={10}/> {task.locationTrigger}</span>}
                    {task.recurrence && <span className="glass px-3 py-1.5 rounded-lg text-[10px] font-black text-purple-300 flex items-center gap-1.5 uppercase tracking-tighter"><Repeat size={10}/> {task.recurrence}</span>}
                  </div>
                </div>
                <button onClick={(e) => { e.stopPropagation(); onDelete(task.id); }} className="p-2 text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={20}/></button>
              </div>
            </div>
        );
      })}
    </div>
  );
};

export default TaskList;

